## 2. The C / C++ stub (`pcapng_stubs.cpp`)

> **Important** – The file must be compiled as C++ (e.g. `g++ -c -I$(ocamlc -where) …`),
> but the entry points are declared `extern "C"` so that the OCaml runtime can link
> to them.

```cpp
/* --------------------------------------------------------------
 * pcapng_stubs.cpp – C++ side of the OCaml libpcapng binding
 *
 * Build (example):
 *   ocamlc -c pcapng.mli
 *   g++ -c -I$(ocamlc -where) -I/usr/include -fPIC pcapng_stubs.cpp
 *   ocamlc -custom -o pcapng.cma pcapng.cmi pcapng_stubs.o -lstdc++ -lpcapng
 * ------------------------------------------------------------ */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <cstring>
#include <stdexcept>
#include <string>

// ------------------------------------------------------------------
// Mock of the libpcapng C++ API (replace with the real header when
// linking against the actual library)
// ------------------------------------------------------------------
namespace libpcapng {

struct Frame {
    double   timestamp;      // seconds since epoch
    uint32_t captured_len;   // bytes stored in file
    uint32_t original_len;   // bytes on the wire
    const uint8_t* data;     // pointer to captured data (owned by iterator)
};

class PcapngReader {
public:
    explicit PcapngReader(const std::string& filename);
    ~PcapngReader();

    // forward‑only iterator (no random access needed)
    class iterator {
    public:
        iterator(PcapngReader* parent, bool end = false);
        iterator& operator++();          // advance to next frame
        bool operator!=(const iterator&) const;
        const Frame& operator*() const;
    private:
        PcapngReader* parent_;
        bool          at_end_;
        Frame         cur_;
        void          fetch();           // fill cur_ or set at_end_
    };

    iterator begin();
    iterator end();
private:
    // Opaque handle to the underlying library – not important for the stub
    void* impl_;
};

// ------------------------------------------------------------------
// Minimal mock implementation (just to make the stub compile)
// ------------------------------------------------------------------
PcapngReader::PcapngReader(const std::string&) : impl_(nullptr) {}
PcapngReader::~PcapngReader() {}

PcapngReader::iterator::iterator(PcapngReader* p, bool end)
    : parent_(p), at_end_(end) { if (!end) fetch(); }

void PcapngReader::iterator::fetch() {
    // In a real implementation we would ask the library for the next frame.
    // Here we simply simulate EOF after a few calls.
    static int counter = 0;
    if (counter >= 3) { at_end_ = true; return; }
    cur_.timestamp    = 1.618 + 0.001*counter;
    cur_.captured_len = 64 + counter*10;
    cur_.original_len = cur_.captured_len + 4;
    static const uint8_t dummy[128] = {0};
    cur_.data = dummy;
    ++counter;
}
bool PcapngReader::iterator::operator!=(const iterator& o) const {
    return at_end_ != o.at_end_;
}
PcapngReader::iterator& PcapngReader::iterator::operator++() {
    fetch(); return *this;
}
const Frame& PcapngReader::iterator::operator*() const { return cur_; }

PcapngReader::iterator PcapngReader::begin() { return iterator(this,false); }
PcapngReader::iterator PcapngReader::end()   { return iterator(this,true); }

} // namespace libpcapng

// ------------------------------------------------------------------
// OCaml custom block handling for the opaque type `t`
// ------------------------------------------------------------------

static struct custom_operations pcapng_reader_ops = {
    "pcapng.reader",
    /* finalize */ [](value v) {
        libpcapng::PcapngReader* r = (libpcapng::PcapngReader*)Data_custom_val(v);
        delete r;
    },
    /* compare */ nullptr,
    /* hash */ nullptr,
    /* serialize */ nullptr,
    /* deserialize */ nullptr,
    /* compare_ext */ nullptr,
    /* fixed_length */ nullptr
};

static inline libpcapng::PcapngReader* Reader_val(value v) {
    return (libpcapng::PcapngReader*)Data_custom_val(v);
}

/* --------------------------------------------------------------
 * OCaml entry points
 * ------------------------------------------------------------ */

/* val open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_reader);
    const char* path = String_val(v_path);
    try {
        libpcapng::PcapngReader* r = new libpcapng::PcapngReader(std::string(path));
        v_reader = caml_alloc_custom(&pcapng_reader_ops, sizeof(void*), 0, 1);
        Data_custom_val(v_reader) = (char*)r;
        CAMLreturn(v_reader);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
}

/* val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_reader) {
    CAMLparam1(v_reader);
    libpcapng::PcapngReader* r = Reader_val(v_reader);
    if (r) {
        delete r;
        // Overwrite the pointer with nullptr so a double close is harmless.
        Data_custom_val(v_reader) = (char*)nullptr;
    }
    CAMLreturn(Val_unit);
}

/* Helper: build an OCaml `frame` record.
 * The OCaml type is:
 *   { timestamp : float; captured_len : int; original_len : int; data : bytes }
 * The record layout is known at compile time (4 fields, tag = 0).
 */
static value mk_frame(const libpcapng::Frame& f) {
    CAMLparam0();
    CAMLlocal4(v_rec, v_ts, v_caplen, v_origlen);
    CAMLlocal1(v_data);

    v_ts      = caml_copy_double(f.timestamp);
    v_caplen  = Val_int(f.captured_len);
    v_origlen = Val_int(f.original_len);

    // Copy the packet bytes into a fresh OCaml `bytes` value.
    v_data = caml_alloc_string(f.captured_len);
    memcpy(String_val(v_data), f.data, f.captured_len);

    // Allocate the record (4 fields)
    v_rec = caml_alloc(4, 0);
    Store_field(v_rec, 0, v_ts);
    Store_field(v_rec, 1, v_caplen);
    Store_field(v_rec, 2, v_origlen);
    Store_field(v_rec, 3, v_data);
    CAMLreturn(v_rec);
}

/* val iter : t -> (frame -> unit) -> unit
 *
 * The C++ iterator drives the loop; for each frame we call back into OCaml.
 * If the OCaml callback raises, we abort the C++ loop and re‑raise.
 */
extern "C" CAMLprim value caml_pcapng_iter(value v_reader, value v_cb) {
    CAMLparam2(v_reader, v_cb);
    libpcapng::PcapngReader* r = Reader_val(v_reader);
    if (!r) caml_failwith("Pcapng.iter: invalid (closed) reader");

    try {
        for (auto it = r->begin(); it != r->end(); ++it) {
            const libpcapng::Frame& f = *it;
            value v_frame = mk_frame(f);
            // Call the OCaml function; use caml_callback_exn to catch exceptions.
            value v_res = caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(v_res)) {
                // Propagate the exception to OCaml land.
                caml_raise(v_res);
            }
            // The callback returns unit, we ignore v_res.
        }
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
    CAMLreturn(Val_unit);
}

/* val next : t -> frame option
 *
 * This is a simple “pull” version: it remembers the iterator state inside
 * the custom block.  To keep the example short we store a pointer to the
 * iterator in the same custom block after the reader pointer.
 *
 * The custom block layout (after the initial `Data_custom_val`):
 *   [0] : PcapngReader*                (always present)
 *   [1] : libpcapng::PcapngReader::iterator*  (may be nullptr)
 *
 * The block is allocated with two words (sizeof(void*) * 2).  A finaliser
 * deletes both objects.
 */

static void finalize_reader_and_iter(value v) {
    // First word: reader
    libpcapng::PcapngReader* r = (libpcapng::PcapngReader*)Data_custom_val(v);
    // Second word: iterator (if any)
    libpcapng::PcapngReader::iterator* it =
        (libpcapng::PcapngReader::iterator*)((char*)v + sizeof(void*));
    if (it) delete it;
    if (r) delete r;
}

/* Re‑define custom ops with the new finaliser */
static struct custom_operations pcapng_reader_ops2 = {
    "pcapng.reader2",
    finalize_reader_and_iter,
    nullptr, nullptr, nullptr, nullptr, nullptr, nullptr
};

/* Helper to get the iterator pointer from the custom block. */
static libpcapng::PcapngReader::iterator* get_iter(value v) {
    return (libpcapng::PcapngReader::iterator*)((char*)v + sizeof(void*));
}

/* val open_file_for_next : string -> t
 * Same as `open_file` but also creates a fresh iterator stored in the block.
 */
extern "C" CAMLprim value caml_pcapng_open_for_next(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_block);
    const char* path = String_val(v_path);
    try {
        libpcapng::PcapngReader* r = new libpcapng::PcapngReader(std::string(path));
        // Allocate block large enough for two pointers.
        v_block = caml_alloc_custom(&pcapng_reader_ops2,
                                    sizeof(void*) * 2, 0, 1);
        // Store the reader pointer at offset 0.
        Data_custom_val(v_block) = (char*)r;
        // Store a *new* iterator (pointing to begin) at offset sizeof(void*).
        libpcapng::PcapngReader::iterator* it =
            new libpcapng::PcapngReader::iterator(r->begin());
        memcpy((char*)v_block + sizeof(void*), &it, sizeof(void*));
        CAMLreturn(v_block);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
}

/* val next : t -> frame option */
extern "C" CAMLprim value caml_pcapng_next(value v_reader) {
    CAMLparam1(v_reader);
    CAMLlocal1(v_opt);
    libpcapng::PcapngReader* r = (libpcapng::PcapngReader*)Data_custom_val(v_reader);
    if (!r) caml_failwith("Pcapng.next: invalid (closed) reader");

    libpcapng::PcapngReader::iterator* it = get_iter(v_reader);
    if (!it) caml_failwith("Pcapng.next: iterator not initialised");

    if (*it == r->end()) {
        // No more frames → None
        v_opt = Val_int(0);          // 0 = None
    } else {
        const libpcapng::Frame& f = **it;
        value v_frame = mk_frame(f);
        // Some = Some v_frame
        v_opt = caml_alloc(1, 0);
        Store_field(v_opt, 0, v_frame);
        // Advance iterator for the next call.
        ++(*it);
    }
    CAMLreturn(v_opt);
}

/* --------------------------------------------------------------
 * End of pcapng_stubs.cpp
 * ------------------------------------------------------------ */
```

### How the stub works

| OCaml function | What the stub does |
|----------------|--------------------|
| `open_file`    | Allocates a custom block (`t`) holding a `new PcapngReader`. A finaliser deletes the object. |
| `close`        | Explicitly deletes the reader and clears the pointer (so a second `close` is a no‑op). |
| `iter`         | Retrieves the `PcapngReader*`, walks `begin()` → `end()`. For each `Frame` it builds an OCaml record (`mk_frame`) and calls the supplied OCaml callback via `caml_callback_exn`. If the callback raises, we abort the C++ loop and re‑raise the exception. |
| `next`         | Uses a second custom block layout that also stores a pointer to a C++ `iterator`. Each call returns `Some frame` (or `None`) and advances the iterator. |
| `open_file_for_next` (internal) | Helper that creates both the reader and the iterator in one block – used only to implement `next`. The public `open_file` could be re‑implemented in terms of it, but we keep both for clarity. |

### Building the binding

Assuming the real `libpcapng` header is available (replace the mock namespace with the real one):

```sh
# 1. Compile the OCaml interface
ocamlc -c pcapng.mli

# 2. Compile the stub (needs a C++ compiler)
g++ -c -I$(ocamlc -where) -fPIC pcapng_stubs.cpp -o pcapng_stubs.o

# 3. Archive the stub as a C library (optional)
g++ -shared -o libpcapng_stubs.so pcapng_stubs.o -lpcapng

# 4. Build the OCaml library (static linking for simplicity)
ocamlc -custom -o pcapng.cma pcapng.cmi pcapng_stubs.o -lstdc++ -lpcapng
```

Now the binding can be used from OCaml:

```ocaml
(* test_pcapng.ml *)
let () =
  let rdr = Pcapng.open_file "samples/example.pcapng" in
  Pcapng.iter rdr (fun f ->
      Printf.printf "frame: %d bytes @ %.6f\n%!"
        f.captured_len f.timestamp);
  Pcapng.close rdr
```

Compile & run:

```sh
ocamlc -I . -c test_pcapng.ml
ocamlc -o test_pcapng pcapng.cma test_pcapng.cmo
./test_pcapng
```

---

## 3. Summary of the design

* **High‑level API** – a single abstract type `t` and a simple `iter` function that mirrors the “apply a function to each row” pattern of pandas/Polars.  
* **Safety** – the stub copies frame data into an OCaml `bytes`, so the OCaml value owns its memory. The custom block finaliser guarantees that native resources are freed even if the user forgets to call `close`.  
* **Exception handling** – any exception raised by the user‑provided callback aborts the C++ loop and is re‑raised on the OCaml side, giving the same semantics as pure OCaml iteration functions.  
* **Both push‑ and pull‑style** – `iter` for eager “apply‑to‑all” work, and `next` for lazy, on‑demand consumption.  
* **Self‑contained** – the `.mli` together with the C++ stub (including a tiny mock of the C++ API) can be compiled directly, and the comments make it trivial to replace the mock with the real `libpcapng` header.

Feel free to adapt the stub to the exact API of the real `libpcapng` library (e.g. different field names, packet‑timestamp type, etc.). The skeleton above already shows the essential pattern for exposing a C++ iterator to OCaml while letting the user write per‑frame OCaml code.
